package travelcare_agent.evaluation.dto; import travelcare_agent.evaluation.entity.EvaluationCaseResult; public record EvaluationCaseResultResponse(Long id,Long runId,Long caseId,String caseKey,Long sourceTraceId,Long dryRunTraceId,Long diffId,String status,String scoresJson,String failureReason,String riskLevel){public static EvaluationCaseResultResponse from(EvaluationCaseResult v){return new EvaluationCaseResultResponse(v.getId(),v.getRunId(),v.getCaseId(),v.getCaseKey(),v.getSourceTraceId(),v.getDryRunTraceId(),v.getDiffId(),v.getStatus(),v.getScoresJson(),v.getFailureReason(),v.getRiskLevel());}}
